macro.command:
let actor = canvas.tokens.controlled[0]?.actor;

if (!actor) {
  ui.notifications.warn("Seleziona un token!");
  return;
}

// Cerca lo status "Prone" tra gli effetti attivi
let proneEffect = actor.effects.find(e => e.name === "Prone");

if (proneEffect) {
  // Rimuove l'effetto
  await proneEffect.delete();
  ui.notifications.info("Condizione 'Prone' rimossa.");
} else {
  ui.notifications.info("Il token non è Prone.");
}

let actor = canvas.tokens.controlled[0]?.actor;

if (!actor) {
  ui.notifications.warn("Seleziona un token!");
  return;
}

// Verifica se l'attore ha lo status "Prone"
let proneEffect = actor.effects.find(e => e.label === "Prone");

if (proneEffect) {
  // Rimuove lo status "Prone"
  proneEffect.delete();
}
